values ('rrdeco-com-br-31063427', 'rrdeco-com-br-31063427', '2026-w24', 'RR Antiguidades Antigo quadro representando cena de Mulher assinada pelo artista KONN. Peca estimada da decada de 60. Dimensao aproximada de: externa com altura de 71,0 cms x comprimento de 56,0 cms. Peca em otimo estado. Peca com protecao em vidro. Segundo informacoes dos correios pecas com mais de 70 cms tem um acrescimo de 80 reais para o envio.  Cod 9021', 400.0, 'lance inicial r$ 400', 'rrdeco.com.br', 'https://rrdeco.com.br/peca.asp?Id=31063427', 'https://d1o6h00a1h5k7q.cloudfront.net/imagens/img_m/62091/31063427.jpg', '2026-07-11T13:00', 69.0, 'alta', 'baixo', 3677.14, 0, 'queued', '{"item_type": "cristal_vidro", "macro_category": "Decoração", "designer": "moveis_cimo", "attribution_strength": "DOCUMENTED", "condition_tier": null, "size_class": null, "uf": "RJ", "house_name": null, "est_resale_base": 12060.0, "est_total_cost": null, "est_gross_profit": null, "est_gross_margin_pct": 0.9264, "max_bid_40pct": 4077.14, "confidence": null, "signal": "BUY_NOW", "signal_reasons": null, "entry_reasons": ["vibe decorativa", "oportunidade buy_now"], "risk_reasons": []}'::jsonb, '2026-06-14T00:00:24Z')
