values ('marirodriguesleiloeira-com-br-31120254', 'marirodriguesleiloeira-com-br-31120254', '2026-w24', 'BACCARAT  Conjunto com 8 taças para vinho em cristal overlay rubi, composto por delicadas taças de bojo arredondado com rica lapidação em reservas ovais translúcidas, apoiadas sobre hastes transparentes moldadas e bases circulares. Elegante trabalho em cristal vermelho translúcido, característico da refinada produção francesa da Baccarat, revelando notável efeito luminoso e sofisticado acabamento. Conjunto de grande apelo decorativo e colecionável, representativo da tradição vidreira francesa do século XX. Medidas: 11,5 cm.', 1800.0, 'lance inicial r$ 1.800', 'marirodriguesleiloeira.com.br', 'https://marirodriguesleiloeira.com.br/peca.asp?Id=31120254', 'https://d1o6h00a1h5k7q.cloudfront.net/imagens/img_m/61251/31120254.jpg', '2026-06-16T15:00', 58.0, 'alta', 'medio', null, 0, 'queued', '{"item_type": "cristal_vidro", "macro_category": "Decoração", "designer": null, "attribution_strength": "NONE", "condition_tier": null, "size_class": null, "uf": "RJ", "house_name": null, "est_resale_base": 153.0, "est_total_cost": null, "est_gross_profit": null, "est_gross_margin_pct": -23.8148, "max_bid_40pct": 0.0, "confidence": null, "signal": "AVOID", "signal_reasons": null, "entry_reasons": ["vibe decorativa", "cristal/vidro de marca"], "risk_reasons": ["margem apertada"]}'::jsonb, '2026-06-14T00:00:24Z')
