values ('antiguitati-com-br-31003527', 'antiguitati-com-br-31003527', '2026-w24', 'Cristalerie Baccarat - Par de raros copos para vinho do porto, com apenas 8 cm de altura, raros por seu incomum tamanho, feitos em cristal overlay um azul e um vermelho, pés soprados, lapidação dita "dedão".', 360.0, 'lance atual r$ 360', 'antiguitati.com.br', 'https://antiguitati.com.br/peca.asp?Id=31003527', 'https://d1o6h00a1h5k7q.cloudfront.net/imagens/img_m/62159/31003527.jpg', '2026-06-18T19:00', 57.6, 'alta', 'medio', null, 1, 'queued', '{"item_type": "cristal_vidro", "macro_category": "Decoração", "designer": null, "attribution_strength": "NONE", "condition_tier": null, "size_class": null, "uf": "RJ", "house_name": null, "est_resale_base": 153.0, "est_total_cost": null, "est_gross_profit": null, "est_gross_margin_pct": -5.1481, "max_bid_40pct": 0.0, "confidence": null, "signal": "AVOID", "signal_reasons": null, "entry_reasons": ["vibe decorativa", "cristal/vidro de marca"], "risk_reasons": ["margem apertada"]}'::jsonb, '2026-06-14T00:00:24Z')
