values ('marirodriguesleiloeira-com-br-31130465', 'marirodriguesleiloeira-com-br-31130465', '2026-w24', 'BOLSA FEMININA  Bolsa de mão em prata de lei, com estrutura superior rígida ricamente trabalhada em filigrana e relevos ornamentais, apresentando vazados decorativos e cartelas com motivos florais e arabescados. Corpo confeccionado em malha de prata (chain mail), de caimento flexível, com borda inferior ondulada e acabamento delicado. Acompanha alça articulada em elos de prata, integrada à armação. Fecho tipo clique, funcional. Medidas: 25 cm x 18 cm. Peso: 242 g.', 980.0, 'lance atual r$ 980', 'marirodriguesleiloeira.com.br', 'https://marirodriguesleiloeira.com.br/peca.asp?Id=31130465', 'https://d1o6h00a1h5k7q.cloudfront.net/imagens/img_m/61251/31130465.jpg', '2026-06-17T15:00', 57.0, 'alta', 'medio', null, 1, 'queued', '{"item_type": "prata_metal", "macro_category": "Decoração", "designer": null, "attribution_strength": "NONE", "condition_tier": null, "size_class": null, "uf": "RJ", "house_name": null, "est_resale_base": 216.0, "est_total_cost": null, "est_gross_profit": null, "est_gross_margin_pct": -11.7667, "max_bid_40pct": 0.0, "confidence": null, "signal": "AVOID", "signal_reasons": null, "entry_reasons": ["vibe decorativa", "prata com teor"], "risk_reasons": ["margem apertada"]}'::jsonb, '2026-06-14T00:00:24Z')
