values ('marirodriguesleiloeira-com-br-31125950', 'marirodriguesleiloeira-com-br-31125950', '2026-w24', 'Caixa retangular confeccionada em prata de lei 900 mls, com tampa levemente abaulada e superfície lisa, de linhas sóbrias e elegantes. Apresenta estrutura robusta, com dobradiça posterior contínua e fecho frontal simples, mantendo estética limpa e funcional. Interior igualmente em prata, evidenciando marcas naturais de uso e pátina compatível com o tempo. Medidas: 5,5 cm (A) x 12 cm (L) x 14,5 cm (comp). Peso 394 g', 2200.0, 'lance atual r$ 2.200', 'marirodriguesleiloeira.com.br', 'https://marirodriguesleiloeira.com.br/peca.asp?Id=31125950', 'https://d1o6h00a1h5k7q.cloudfront.net/imagens/img_m/61251/31125950.jpg', '2026-06-17T15:00', 57.0, 'alta', 'medio', null, 1, 'queued', '{"item_type": "prata_metal", "macro_category": "Decoração", "designer": null, "attribution_strength": "NONE", "condition_tier": null, "size_class": null, "uf": "RJ", "house_name": null, "est_resale_base": 216.0, "est_total_cost": null, "est_gross_profit": null, "est_gross_margin_pct": -26.0, "max_bid_40pct": 0.0, "confidence": null, "signal": "AVOID", "signal_reasons": null, "entry_reasons": ["vibe decorativa", "prata com teor"], "risk_reasons": ["margem apertada"]}'::jsonb, '2026-06-14T00:00:24Z')
