values ('vmescritarteleiloes-com-br-31088240', 'vmescritarteleiloes-com-br-31088240', '2026-w24', 'Par de porta-ovo poché, com présentoir, lavrado em prata de lei norte-americana, contraste "Sterling", punção do prateiro oficial da Casa Branca de Rhode Island, Jabez Gorham (estabelecido desde 1831), teor de toque 0,980, elegantemente lavrado com copo fenestrado em desenhos de arabescos e alça recurva de aba alta, e présentoir ornado com monograma cursivo "CBJC". Timbres de numeração de modelos "A5550". Peso total de 106 g. Estados Unidos, período compreendido entre os anos de 1890 e 1920.', 750.0, 'lance atual r$ 750', 'vmescritarteleiloes.com.br', 'https://vmescritarteleiloes.com.br/peca.asp?Id=31088240', 'https://d1o6h00a1h5k7q.cloudfront.net/imagens/img_m/62422/31088240.jpg', '2026-06-17T20:00', 57.0, 'alta', 'medio', null, 2, 'queued', '{"item_type": "prata_metal", "macro_category": "Decoração", "designer": null, "attribution_strength": "NONE", "condition_tier": null, "size_class": null, "uf": "SP", "house_name": null, "est_resale_base": 216.0, "est_total_cost": null, "est_gross_profit": null, "est_gross_margin_pct": -9.0833, "max_bid_40pct": 0.0, "confidence": null, "signal": "AVOID", "signal_reasons": null, "entry_reasons": ["vibe decorativa", "prata com teor"], "risk_reasons": ["margem apertada"]}'::jsonb, '2026-06-14T00:00:24Z')
