values ('vmescritarteleiloes-com-br-31077586', 'vmescritarteleiloes-com-br-31077586', '2026-w24', 'Urna, com tampa, de prata de lei brasileira, contraste "MFS Coroa", teor de toque 0,925, lavrada ao estilo das antigas peças alemãs de Hanau, composta de base circular ornada com acantos, sustentada por tripé em garras com ornatos, encimada por fuste central em figurações mitológicas de querubins, copo em fino trabalho de cinzelamentos e repuxes com barrado de desenhos de folhas e penachos estilizados, arrematado na parte superior por cercadura de motivos florais e tampa decorada "en suite" com pega em pequena escultura de pássaro sobre pétala invertida. 10,5 cm de diâmetro e 26 cm de altura. Peso de 355 g. Brasil, década de 1940.', 2600.0, 'lance atual r$ 2.600', 'vmescritarteleiloes.com.br', 'https://vmescritarteleiloes.com.br/peca.asp?Id=31077586', 'https://d1o6h00a1h5k7q.cloudfront.net/imagens/img_m/62422/31077586.jpg', '2026-06-17T20:00', 57.0, 'alta', 'medio', null, 1, 'queued', '{"item_type": "escultura", "macro_category": "Arte", "designer": null, "attribution_strength": "NONE", "condition_tier": null, "size_class": null, "uf": "SP", "house_name": null, "est_resale_base": 288.0, "est_total_cost": null, "est_gross_profit": null, "est_gross_margin_pct": -22.8095, "max_bid_40pct": 0.0, "confidence": null, "signal": "AVOID", "signal_reasons": null, "entry_reasons": ["vibe decorativa", "prata com teor"], "risk_reasons": ["margem apertada"]}'::jsonb, '2026-06-14T00:00:24Z')
