values ('marirodriguesleiloeira-com-br-31120072', 'marirodriguesleiloeira-com-br-31120072', '2026-w24', 'Cinzeiro de prata portuguesa do Porto, contraste Águia, II Título, 833 mls,  lavrado ao estilo das peças do período regencial luso D. José I, com aba recortada e barrado em ricos repuxes ornados por conchas, volutas e folhas de acanto. Corpo moldado com quatro apoios para cigarros e centro delicadamente gravado com elementos vegetalistas. Trabalho de elegante execução, inspirado na ourivesaria barroca portuguesa do século XVIII. Portugal, década de 1930. Medidas: 17,5 x 17,5 cm. Peso: 154 g.', 900.0, 'lance inicial r$ 900', 'marirodriguesleiloeira.com.br', 'https://marirodriguesleiloeira.com.br/peca.asp?Id=31120072', 'https://d1o6h00a1h5k7q.cloudfront.net/imagens/img_m/61251/31120072.jpg', '2026-06-16T15:00', 55.0, 'media', 'medio', null, 0, 'queued', '{"item_type": "prata_metal", "macro_category": "Decoração", "designer": null, "attribution_strength": "NONE", "condition_tier": null, "size_class": null, "uf": "RJ", "house_name": null, "est_resale_base": 216.0, "est_total_cost": null, "est_gross_profit": null, "est_gross_margin_pct": -10.8333, "max_bid_40pct": 0.0, "confidence": null, "signal": "AVOID", "signal_reasons": null, "entry_reasons": ["vibe decorativa", "prata com teor"], "risk_reasons": ["margem apertada"]}'::jsonb, '2026-06-14T00:00:24Z')
