values ('vmescritarteleiloes-com-br-31093299', 'vmescritarteleiloes-com-br-31093299', '2026-w24', 'Lote composto de três xícaras para chá, e seus pires, em porcelana esmaltada portuguesa, manufatura "Vista Alegre", decoradas com motivos florais em policromia e frisos em douração a ouro, sobre fundo de cor branca. Portugal, período compreendido entre os anos de 1947 e 1968.', 100.0, 'lance atual r$ 100', 'vmescritarteleiloes.com.br', 'https://vmescritarteleiloes.com.br/peca.asp?Id=31093299', 'https://d1o6h00a1h5k7q.cloudfront.net/imagens/img_m/62422/31093299.jpg', '2026-06-18T20:00', 52.0, 'media', 'medio', null, 1, 'queued', '{"item_type": "porcelana_ceramica", "macro_category": "Decoração", "designer": null, "attribution_strength": "NONE", "condition_tier": null, "size_class": null, "uf": "SP", "house_name": null, "est_resale_base": 126.0, "est_total_cost": null, "est_gross_profit": null, "est_gross_margin_pct": -2.125, "max_bid_40pct": 0.0, "confidence": null, "signal": "AVOID", "signal_reasons": null, "entry_reasons": ["vibe decorativa", "porcelana de manufatura"], "risk_reasons": ["margem apertada"]}'::jsonb, '2026-06-14T00:00:24Z')
