values ('antiguitati-com-br-31030237', 'antiguitati-com-br-31030237', '2026-w24', 'Sévres - Rara e excepcional caixa em porcelana de Sévres, marca no fundo, letra de data "F" (1758-1759), finamente decorada em policromia e farto ouro em relevo, sua tampa com cena galante, assinada "Henry", ferragens em bronze ormolu, excelente estado de conservação, peça com alta cotação internacional, uma quase idêntica foi vendida no leilão "Abel" em Los Angeles em julho de 2022 por US$ 2.2250,00, vide print nas fotos adicionais, 24 x 15 cm e alt. 7,5 cm', 4500.0, 'lance inicial r$ 4.500', 'antiguitati.com.br', 'https://antiguitati.com.br/peca.asp?Id=31030237', 'https://d1o6h00a1h5k7q.cloudfront.net/imagens/img_m/62159/31030237.jpg', '2026-06-18T19:00', 52.0, 'media', 'medio', null, 0, 'queued', '{"item_type": "porcelana_ceramica", "macro_category": "Decoração", "designer": null, "attribution_strength": "NONE", "condition_tier": null, "size_class": null, "uf": "RJ", "house_name": null, "est_resale_base": 126.0, "est_total_cost": null, "est_gross_profit": null, "est_gross_margin_pct": -66.2917, "max_bid_40pct": 0.0, "confidence": null, "signal": "AVOID", "signal_reasons": null, "entry_reasons": ["vibe decorativa", "porcelana de manufatura"], "risk_reasons": ["margem apertada"]}'::jsonb, '2026-06-14T00:00:24Z')
