values ('ciclosleiloes-com-br-31023634', 'ciclosleiloes-com-br-31023634', '2026-w24', 'Eamag Schönwald Bavaria- elegante conjunto de café e chá em porcelana,contendo  1 bule ,1 mantegueira, 6 pratos, caracterizado por um acabamento clássico em branco com um friso azul-cobalto e delicadas guirlandas douradas.Esse padrão ornamental com bordas azuis e arabescos dourados foi produzido historicamente por tradicionais manufaturas europeias de porcelana de alta qualidade, incluindo marcas da região da Baviera na Alemanha.', 298.0, 'lance inicial r$ 298', 'ciclosleiloes.com.br', 'https://ciclosleiloes.com.br/peca.asp?Id=31023634', 'https://d1o6h00a1h5k7q.cloudfront.net/imagens/img_m/61115/31023634.jpg', '2026-06-18T14:00', 52.0, 'media', 'medio', null, 0, 'queued', '{"item_type": "porcelana_ceramica", "macro_category": "Decoração", "designer": null, "attribution_strength": "NONE", "condition_tier": null, "size_class": null, "uf": "RS", "house_name": null, "est_resale_base": 126.0, "est_total_cost": null, "est_gross_profit": null, "est_gross_margin_pct": -5.0125, "max_bid_40pct": 0.0, "confidence": null, "signal": "AVOID", "signal_reasons": null, "entry_reasons": ["vibe decorativa", "porcelana de manufatura"], "risk_reasons": ["margem apertada"]}'::jsonb, '2026-06-14T00:00:24Z')
