values ('rrdeco-com-br-31063038', 'rrdeco-com-br-31063038', '2026-w24', 'Antiga e rara sopeira confeccionada em porcelana Francesa. Peca com friso dourado em ouro 24kt. Peca assinada ao fundo pela renomada manufatura Francesa Limoges J.Boyer. Peca estimada da decada de 70.  Dimensoes aproximadas de: comprimento de alca a alca de 32,0 cms x largura de 18,0 cms x altura total com a tampa de 13,0 cms. Peca em otimo estado sem bicados ou trincas. Peca com leves desgastes do tempo na douracao.  COD 7825', 760.0, 'lance inicial r$ 760', 'rrdeco.com.br', 'https://rrdeco.com.br/peca.asp?Id=31063038', 'https://d1o6h00a1h5k7q.cloudfront.net/imagens/img_m/62091/31063038.jpg', '2026-07-09T18:00', 46.0, 'media', 'alto', null, 0, 'queued', '{"item_type": "porcelana_ceramica", "macro_category": "Decoração", "designer": null, "attribution_strength": "NONE", "condition_tier": null, "size_class": null, "uf": "RJ", "house_name": null, "est_resale_base": 126.0, "est_total_cost": null, "est_gross_profit": null, "est_gross_margin_pct": -28.4167, "max_bid_40pct": 0.0, "confidence": null, "signal": "AVOID", "signal_reasons": null, "entry_reasons": ["vibe decorativa", "porcelana de manufatura"], "risk_reasons": ["estado/restauro", "margem apertada"]}'::jsonb, '2026-06-14T00:00:24Z')
