values ('artemaiorleiloes-com-br-31141006', 'artemaiorleiloes-com-br-31141006', '2026-w24', 'Maria Carmen - 1935/2014 - Quadro óleo sobre eucatex, medindo 49x73cm, com moldura, ano 1988. Maria Carmen de Queirós Bastos, foi uma artista plástica pernambucana, nasceu em Recife em 1935. Ela foi pintora, desenhista e escultora, tendo estudado escultura no Rio de Janeiro e desenho com grandes mestres em Pernambuco, como Abelardo da Hora, faleceu em 2014.', 2000.0, 'lance inicial r$ 2.000', 'artemaiorleiloes.com.br', 'https://artemaiorleiloes.com.br/peca.asp?Id=31141006', 'https://d1o6h00a1h5k7q.cloudfront.net/imagens/img_m/62371/31141006.jpg', '2026-06-16T19:00', 46.0, 'media', 'medio', null, 0, 'queued', '{"item_type": "escultura", "macro_category": "Arte", "designer": null, "attribution_strength": "NONE", "condition_tier": null, "size_class": null, "uf": "PE", "house_name": null, "est_resale_base": 288.0, "est_total_cost": null, "est_gross_profit": null, "est_gross_margin_pct": -17.8095, "max_bid_40pct": 0.0, "confidence": null, "signal": "AVOID", "signal_reasons": null, "entry_reasons": ["vibe decorativa"], "risk_reasons": ["margem apertada"]}'::jsonb, '2026-06-14T00:00:24Z')
