values ('garimpoleiloes-com-br-30952411', 'garimpoleiloes-com-br-30952411', '2026-w24', 'Carmem Flora  (Nascida no RS, radicada no RJ, escultora e pintora, recebeu inúmeros prêmios: Medalha de Ouro (escultura) - Academia de Belas Artes, Menção honrosa (pintura) XXVI Salão de Belas Artes do Clube Naval, Medalha de Bronze (pintura) Sociedade Brasileira de Belas Artes, Medalha de Ouro (pintura) - XIV Salão de Itatiaia-  Quadro Óleo s/tela, de figura masculina com realismo contemporâneo, focando na forma humana e na expressão emocional.  78,5 x 64 cm s/moldura e 104 x 90 cm c/moldura', 1500.0, 'lance inicial r$ 1.500', 'garimpoleiloes.com.br', 'https://garimpoleiloes.com.br/peca.asp?Id=30952411', 'https://d1o6h00a1h5k7q.cloudfront.net/imagens/img_m/62132/30952411.jpg', '2026-06-16T19:00', 46.0, 'media', 'medio', null, 0, 'queued', '{"item_type": "escultura", "macro_category": "Arte", "designer": null, "attribution_strength": "NONE", "condition_tier": null, "size_class": null, "uf": "RS", "house_name": null, "est_resale_base": 288.0, "est_total_cost": null, "est_gross_profit": null, "est_gross_margin_pct": -13.6429, "max_bid_40pct": 0.0, "confidence": null, "signal": "AVOID", "signal_reasons": null, "entry_reasons": ["vibe decorativa"], "risk_reasons": ["margem apertada"]}'::jsonb, '2026-06-14T00:00:24Z')
