values ('marirodriguesleiloeira-com-br-31120179', 'marirodriguesleiloeira-com-br-31120179', '2026-w24', 'A. NOTARI - Majestosa escultura em liga metálica representando leopardo em atitude de ataque, executada em vigoroso estilo Art Déco, com linhas facetadas e composição de forte apelo geométrico, características marcantes da escultura decorativa europeia da segunda metade do século XX. A peça apresenta elegante pátina em tonalidades esverdeadas e repousa sobre base retangular em mármore negro, conferindo imponência e equilíbrio visual ao conjunto. Assinada A. Notari. Europa, c. 1970. Medidas: 33 x 12 cm. Obs.: apresenta rachadura na região central do corpo.', 3000.0, 'lance inicial r$ 3.000', 'marirodriguesleiloeira.com.br', 'https://marirodriguesleiloeira.com.br/peca.asp?Id=31120179', 'https://d1o6h00a1h5k7q.cloudfront.net/imagens/img_m/61251/31120179.jpg', '2026-06-16T15:00', 46.0, 'media', 'alto', null, 0, 'queued', '{"item_type": "escultura", "macro_category": "Arte", "designer": null, "attribution_strength": "NONE", "condition_tier": null, "size_class": null, "uf": "RJ", "house_name": null, "est_resale_base": 288.0, "est_total_cost": null, "est_gross_profit": null, "est_gross_margin_pct": -26.1429, "max_bid_40pct": 0.0, "confidence": null, "signal": "AVOID", "signal_reasons": null, "entry_reasons": ["vibe decorativa", "escultura de época"], "risk_reasons": ["estado/restauro", "margem apertada"]}'::jsonb, '2026-06-14T00:00:24Z')
