values ('velhooesteantiguidades-com-br-31039147', 'velhooesteantiguidades-com-br-31039147', '2026-w24', 'França - Raro Sifão / Garrafa de Água de Seltz Francesa (Século XIX)  Hérault Paris Peça histórica legítima da segunda metade do século XIX (circa 1860/1880), fabricada na França. Este aparelho de porcelana pesada possui o clássico sistema de dois compartimentos internos independentes, utilizado na época para gerar água gaseificada de forma doméstica através de reação química. Autenticidade: Carimbo original na base intacto: " Appareil à Eau de Seltz - Déposé - Herault Paris" Material: Porcelana branca espessa de alta qualidade com detalhes esculpidos em relevo.21 cm de altura e 19 cm da alça ao bico.', 65.0, 'lance atual r$ 65', 'velhooesteantiguidades.com.br', 'https://velhooesteantiguidades.com.br/peca.asp?Id=31039147', 'https://d1o6h00a1h5k7q.cloudfront.net/imagens/img_m/62312/31039147.jpg', '2026-06-15T19:00', 45.6, 'media', 'medio', null, 1, 'queued', '{"item_type": "luminaria_lustre", "macro_category": "Decoração", "designer": null, "attribution_strength": "NONE", "condition_tier": null, "size_class": null, "uf": "SC", "house_name": null, "est_resale_base": 360.0, "est_total_cost": null, "est_gross_profit": null, "est_gross_margin_pct": -1.61, "max_bid_40pct": 0.0, "confidence": null, "signal": "AVOID", "signal_reasons": null, "entry_reasons": ["vibe decorativa"], "risk_reasons": ["margem apertada"]}'::jsonb, '2026-06-14T00:00:24Z')
