values ('rioarteleiloes-com-br-31124607', 'rioarteleiloes-com-br-31124607', '2026-w24', 'APARELHO DE JANTAR VISTA ALEGRE EM PORCELANA DECORADA, 52 PEÇAS.Importante conjunto em porcelana Vista Alegre, ricamente decorado em policromia vibrante, destacando bordaduras em tons de azul, amarelo, vermelho e branco, com ornamentação frutal estilizada de inspiração mediterrânea. Composto por 12 pratos fundos, 18 pratos rasos, 18 pratos de sobremesa, 2 saladeiras e 3 travessas. Peças de desenho elegante e acabamento refinado, características da tradicional manufatura portuguesa, unindo expressivo apelo visual e funcionalidade. Saladeira 26 centímetros de diâmetro,  Travessa 32 x 26 centímetros.', 2700.0, 'lance atual r$ 2.700', 'rioarteleiloes.com.br', 'https://rioarteleiloes.com.br/peca.asp?Id=31124607', 'https://d1o6h00a1h5k7q.cloudfront.net/imagens/img_m/62093/31124607.jpg', null, 45.0, 'media', 'medio', null, 25, 'queued', '{"item_type": "porcelana_ceramica", "macro_category": "Decoração", "designer": null, "attribution_strength": "NONE", "condition_tier": null, "size_class": null, "uf": null, "house_name": null, "est_resale_base": 126.0, "est_total_cost": null, "est_gross_profit": null, "est_gross_margin_pct": -40.0417, "max_bid_40pct": 0.0, "confidence": null, "signal": "AVOID", "signal_reasons": null, "entry_reasons": ["vibe decorativa", "porcelana de manufatura"], "risk_reasons": ["margem apertada", "competição alta"]}'::jsonb, '2026-06-14T00:00:24Z')
