values ('interiorantigo-com-br-31100161', 'interiorantigo-com-br-31100161', '2026-w24', 'Lustre, Carlo Montalto - Produzido em metal, apresenta desenho marcante e estrutura característica das criações do designer, combinando funcionalidade e apelo estético em uma composição equilibrada. A peça possui presença visual destacada e acabamento que valoriza as formas e o material empregado, medindo 80 cm de altura e 49 cm de largura. Por se tratar de uma peça de época, pode conter avarias que realçam sua autenticidade e valor histórico.', 200.0, 'lance atual r$ 200', 'interiorantigo.com.br', 'https://interiorantigo.com.br/peca.asp?Id=31100161', 'https://d1o6h00a1h5k7q.cloudfront.net/imagens/img_m/62488/31100161.jpg', '2026-06-16T20:00', 44.0, 'baixa', 'medio', null, 1, 'queued', '{"item_type": "luminaria_lustre", "macro_category": "Decoração", "designer": null, "attribution_strength": "NONE", "condition_tier": null, "size_class": null, "uf": "SP", "house_name": null, "est_resale_base": 360.0, "est_total_cost": null, "est_gross_profit": null, "est_gross_margin_pct": -2.7037, "max_bid_40pct": 0.0, "confidence": null, "signal": "AVOID", "signal_reasons": null, "entry_reasons": ["vibe decorativa"], "risk_reasons": ["margem apertada"]}'::jsonb, '2026-06-14T00:00:24Z')
