values ('vmescritarteleiloes-com-br-31078685', 'vmescritarteleiloes-com-br-31078685', '2026-w24', 'Floreiro em porcelana esmaltada alemã, manufatura "Meissen", moldado no formato bojudo com alças laterais recurvas altas terminando com elementos decorativos em bagas, ao estilo das peças francesas do período I Império, ornado com reservas opostas em pinturas policromadas de motivos florais, ao padrão "Deutsche Blumen", intercaladas por frisos em douração a ouro. 8,5 cm de diâmetro e 18,3 cm de altura. Na base inferior, marca da manufatura "Cross Swords" em "undeglaze blue" e numeração de decoração "2". Alemanha, período compreendido entre os anos de 1890 e 1930.', 700.0, 'lance inicial r$ 700', 'vmescritarteleiloes.com.br', 'https://vmescritarteleiloes.com.br/peca.asp?Id=31078685', 'https://d1o6h00a1h5k7q.cloudfront.net/imagens/img_m/62422/31078685.jpg', '2026-06-17T20:00', 43.0, 'baixa', 'medio', null, 0, 'queued', '{"item_type": "quadro_pintura", "macro_category": "Arte", "designer": null, "attribution_strength": "NONE", "condition_tier": null, "size_class": null, "uf": "SP", "house_name": null, "est_resale_base": 360.0, "est_total_cost": null, "est_gross_profit": null, "est_gross_margin_pct": -6.9762, "max_bid_40pct": 0.0, "confidence": null, "signal": "AVOID", "signal_reasons": null, "entry_reasons": ["porcelana de manufatura"], "risk_reasons": ["margem apertada"]}'::jsonb, '2026-06-14T00:00:24Z')
